{
  "title": "LLM Ops with Rack: From Rack App to Agentic Project",
  "description": "A practical course that teaches LLM Ops through building a Rack-based application end-to-end (data cleaning → storage → chunking → vector store → retrieval → prompt → LLM generation), with a final Agentic-based project to apply learned concepts.",
  "prerequisites": [
    "Basic familiarity with LLM concepts",
    "Recommended: prior exposure to RAG (there is a dedicated RAG course elsewhere)"
  ],
  "learning_objectives": [
    "Understand Rack components and how they are arranged",
    "Implement a full RAG-style pipeline on a Rack application: cleaning transcripts, storing, loading, chunking, vectorization, retrieval, prompting, and generation",
    "Apply LLM Ops practices throughout the lifecycle using a Rack-based app as the learning vehicle",
    "Build an Agentic-based application as a final project, applying lessons learned"
  ],
  "modules": [
    {
      "id": 0,
      "title": "Course Overview & Flow",
      "objectives": [
        "Describe the full pipeline we will build: clean transcripts → store → load → chunkify → vector store → retrieval → prompt → LLM generation",
        "Explain course structure and final deliverables (Rack app + Agentic project)"
      ],
      "lessons": [
        {
          "title": "Course flow walkthrough",
          "summary": "High-level narrative of the end-to-end flow and where each component fits."
        }
      ]
    },
    {
      "id": 1,
      "title": "Intro to Rack",
      "objectives": [
        "Understand what Rack is and its core components",
        "See how Rack components are arranged in an application"
      ],
      "lessons": [
        {
          "title": "Rack components and architecture",
          "summary": "Overview of Rack; focus on components and arrangement (not an in-depth problem-solution discussion)."
        }
      ]
    },
    {
      "id": 2,
      "title": "Quick RAG Overview",
      "objectives": [
        "Cover retrieval, augmentation, and generation at a high level",
        "Position RAG within the application pipeline"
      ],
      "notes": "RAG is covered quickly here; for depth, students are encouraged to take the dedicated RAG course.",
      "lessons": [
        {
          "title": "Retrieval, Augmentation, Generation (RAG) summary",
          "summary": "Concise explanation of the three RAG steps and how they map to the pipeline."
        }
      ]
    },
    {
      "id": 3,
      "title": "Data Preparation: Cleaning Transcripts",
      "objectives": [
        "Implement a transcript cleaning pipeline",
        "Standardize and prepare text for downstream processing"
      ],
      "lessons": [
        {
          "title": "Cleaning raw transcripts",
          "summary": "Strategies and hands-on exercises for cleaning transcripts (removing noise, normalization, etc.)."
        }
      ]
    },
    {
      "id": 4,
      "title": "Storage and Loading",
      "objectives": [
        "Store cleaned transcripts in a single location",
        "Load transcripts reliably for processing"
      ],
      "lessons": [
        {
          "title": "Designing storage for transcripts",
          "summary": "Best practices for storing and later loading cleaned transcripts."
        }
      ]
    },
    {
      "id": 5,
      "title": "Chunkification",
      "objectives": [
        "Chunk documents into suitable pieces for embedding and retrieval",
        "Decide chunk sizes and overlap strategies"
      ],
      "lessons": [
        {
          "title": "Making chunks",
          "summary": "Hands-on chunking: parameters, trade-offs, and implementation."
        }
      ]
    },
    {
      "id": 6,
      "title": "Vector Store & Embeddings",
      "objectives": [
        "Embed chunks and load them into a vector store",
        "Understand options for vector stores and embedding models"
      ],
      "lessons": [
        {
          "title": "From chunks to vectors",
          "summary": "Embedding strategy and inserting vectors into a vector store."
        }
      ]
    },
    {
      "id": 7,
      "title": "Retrieval & Similarity Search",
      "objectives": [
        "Perform similarity search on the vector store",
        "Retrieve context relevant to user queries"
      ],
      "lessons": [
        {
          "title": "Similarity search operations",
          "summary": "Implementing retrieval, tuning similarity parameters, and returning context."
        }
      ]
    },
    {
      "id": 8,
      "title": "Prompt Construction & Generation",
      "objectives": [
        "Assemble prompts using retrieved context and the user query",
        "Run the generation step with an LLM"
      ],
      "lessons": [
        {
          "title": "Prompt with context and query",
          "summary": "How to augment prompts with retrieval context and call the LLM for final responses."
        },
        {
          "title": "Generation step",
          "summary": "The final generation: sending prompt to the LLM and handling responses."
        }
      ]
    },
    {
      "id": 9,
      "title": "Building the Rack-based Application (Hands-on)",
      "objectives": [
        "Implement the full pipeline in a Rack app: cleaning → storage → load → chunkify → embed → vector store → retrieval → prompt → generation",
        "Observe the LLM Ops lifecycle applied to a Rack-based app"
      ],
      "lessons": [
        {
          "title": "Project setup and architecture",
          "summary": "Scaffold the Rack app and outline components."
        },
        {
          "title": "Implementation sprints",
          "summary": "Step-by-step implementation of each pipeline stage with coding sessions; students may choose to code along or follow demonstrations."
        }
      ],
      "note": "This module is the central learning vehicle for the LLM Ops journey."
    },
    {
      "id": 10,
      "title": "Q&A and Troubleshooting",
      "objectives": [
        "Address common issues and questions",
        "Provide short interactive Q&A windows (e.g., 5-minute question slots)"
      ],
      "lessons": [
        {
          "title": "Common issues and fixes",
          "summary": "Troubleshoot pipeline problems and discuss debugging strategies."
        },
        {
          "title": "Live Q&A",
          "summary": "Instructor-led Q&A; short timeboxed sessions to clarify doubts."
        }
      ]
    },
    {
      "id": 11,
      "title": "Final Project: Agentic-based Application",
      "objectives": [
        "Build an Agentic-based application as the course capstone",
        "Apply LLM Ops principles learned from the Rack app to an Agentic workflow"
      ],
      "lessons": [
        {
          "title": "Agentic project overview",
          "summary": "Project brief: scope, expected deliverables, and success criteria."
        },
        {
          "title": "Project implementation",
          "summary": "Guided build of the Agentic application; integrate retrieval, prompting, and agent orchestration as required."
        }
      ],
      "deliverables": [
        "Working Agentic-based application demonstrating LLM Ops practices",
        "Documentation that ties learnings from the Rack app to the Agentic project"
      ]
    }
  ],
  "assessments_and_deliverables": {
    "continuous": [
      "Completed hands-on exercises for each pipeline stage",
      "Mini-checkpoints during the Rack app build"
    ],
    "final": [
      "Rack-based chatbot application (working demo)",
      "Agentic-based capstone project with documentation"
    ]
  },
  "recommendations": [
    "If you want a deeper dive into RAG, take the dedicated RAG course mentioned",
    "You may code along during the hands-on modules, but observing the initial project start is advised before diving in"
  ]
}

